using System.Globalization;
using System.Text;
using MailKit.Net.Smtp;
using MailKit.Security;
using MimeKit;

namespace orion.Servicios
{
    public enum TipoNotificacion
    {
        Normal,
        Aprobacion,
        Recepcion,
        Rechazo
    }

    public class EmailService : IEmailService
    {
        private readonly IConfiguration _configuration;
        private const string LogoBase64 = "";

        public EmailService(IConfiguration configuration)
        {
            _configuration = configuration;
        }

        public async Task EnviarAsync(
            List<(string Email, string Nombre)> destinatarios,
            string asunto,
            string cuerpoHtml,
            TipoNotificacion tipo = TipoNotificacion.Normal)
        {
            if (destinatarios == null || destinatarios.Count == 0)
            {
                return;
            }

            var settings = _configuration.GetSection("EmailSettings");
            var host = settings["Host"];
            var port = int.TryParse(settings["Port"], out var parsedPort) ? parsedPort : 25;
            var fecha = DateTime.Now.ToString("dd/MM/yyyy", new CultureInfo("es-ES"));

            foreach (var (email, nombre) in destinatarios)
            {
                if (string.IsNullOrWhiteSpace(email))
                {
                    continue;
                }

                try
                {
                    var cuerpoConPlantilla = ConstruirHtml(asunto, cuerpoHtml, fecha);

                    var mensaje = new MimeMessage();
                    mensaje.From.Add(new MailboxAddress("Compras Soalpro", "compras@soalpro.com"));
                    mensaje.To.Add(new MailboxAddress(string.IsNullOrWhiteSpace(nombre) ? email : nombre, email));
                    mensaje.Subject = asunto;
                    mensaje.Body = new BodyBuilder
                    {
                        HtmlBody = cuerpoConPlantilla
                    }.ToMessageBody();

                    using var smtp = new SmtpClient();
                    smtp.ServerCertificateValidationCallback = (s, c, h, e) => true;
                    smtp.Timeout = 30000;

                    await smtp.ConnectAsync(host, port, SecureSocketOptions.None);
                    await smtp.SendAsync(mensaje);
                    await smtp.DisconnectAsync(true);
                }
                catch (Exception ex)
                {
                    Console.WriteLine($"Error enviando correo a {email}: {ex.Message}");
                }
            }
        }

        private static string ConstruirHtml(string asunto, string cuerpoHtml, string fecha)
        {
            return $@"
<!DOCTYPE html>
<html>
<head>
    <meta charset='utf-8' />
    <title>{asunto}</title>
</head>
<body style='margin:0;padding:20px;background:#f3f4f6;font-family:Arial,sans-serif;'>
    <table role='presentation' cellpadding='0' cellspacing='0' width='100%' style='max-width:620px;margin:0 auto;border-collapse:separate;background:#ffffff;border-radius:12px;overflow:hidden;box-shadow:0 2px 12px rgba(0,0,0,0.10);'>
        <tr>
            <td style='background:linear-gradient(135deg, #1e3a6e 0%, #2d5299 100%);padding:20px 24px;'>
                <table role='presentation' cellpadding='0' cellspacing='0' width='100%' style='border-collapse:collapse;'>
                    <tr>
                        <td style='width:64px;vertical-align:middle;'>
                            <img src='data:image/png;base64,{LogoBase64}' width='54' height='54' style='display:block;border-radius:10px;' />
                        </td>
                        <td style='vertical-align:middle;'>
                            <span style='color:#ffffff;font-size:22px;font-weight:700;'>Sistema Orion</span>
                        </td>
                    </tr>
                </table>
            </td>
        </tr>
        <tr>
            <td style='padding:28px 28px 8px;'>
                {cuerpoHtml}
            </td>
        </tr>
        <tr>
            <td style='padding:0 28px;'>
                <hr style='border:0;border-top:1px solid #e5e7eb;margin:8px 0 16px;' />
            </td>
        </tr>
        <tr>
            <td style='padding:0 28px 24px;'>
                <a href='mailto:compras@soalpro.com' style='color:#2563eb;font-size:13px;text-decoration:none;'>
                    compras@soalpro.com
                </a>
            </td>
        </tr>
    </table>
</body>
</html>";
        }

        public static string TextoEstado(string mensaje, TipoNotificacion tipo)
        {
            var color = tipo switch
            {
                TipoNotificacion.Aprobacion => "#16a34a",
                TipoNotificacion.Recepcion => "#0891b2",
                TipoNotificacion.Rechazo => "#dc2626",
                _ => "#1e40af"
            };

            return $"<p style=\"margin:16px 0 0;font-size:15px;font-weight:700;color:{color};\">{mensaje}</p>";
        }

        public static string FilaDato(string icono, string etiqueta, string valor)
        {
            return $@"<p style='margin:10px 0;font-size:14px;color:#374151;'>
  <span style='margin-right:6px;'>{icono}</span>
  <strong>{etiqueta}:</strong> {valor}
</p>";
        }

        public static string Parrafo(string texto)
        {
            return $"<p style=\"margin:10px 0;font-size:14px;color:#374151;\">{texto}</p>";
        }

        public static string TablaProductosSolicitud(
            IEnumerable<(string Descripcion, string Proveedor, decimal Cantidad, string Unidad)> productos)
        {
            var sb = new StringBuilder();
            sb.Append("<table role='presentation' cellpadding='0' cellspacing='0' width='100%' style='border-collapse:separate;border-spacing:0;border:1px solid #e5e7eb;border-radius:8px;margin-top:16px;overflow:hidden;'>");
            sb.Append("<thead><tr style='background:#1e3a6e;color:#ffffff;font-size:12px;'>");
            sb.Append("<th style='padding:9px 12px;text-align:left;'>Descripción</th>");
            sb.Append("<th style='padding:9px 12px;text-align:left;'>Proveedor</th>");
            sb.Append("<th style='padding:9px 12px;text-align:center;'>Cant.</th>");
            sb.Append("<th style='padding:9px 12px;text-align:center;'>Unidad</th>");
            sb.Append("</tr></thead><tbody>");

            var i = 0;
            foreach (var p in productos)
            {
                var bg = i % 2 == 0 ? "#ffffff" : "#f9fafb";
                sb.Append($"<tr style='background:{bg};'>");
                sb.Append($"<td style='padding:9px 12px;font-size:13px;border-bottom:1px solid #f1f5f9;color:#1e293b;'>{p.Descripcion}</td>");
                sb.Append($"<td style='padding:9px 12px;font-size:13px;border-bottom:1px solid #f1f5f9;color:#475569;'>{p.Proveedor}</td>");
                sb.Append($"<td style='padding:9px 12px;font-size:13px;border-bottom:1px solid #f1f5f9;color:#475569;text-align:center;'>{p.Cantidad}</td>");
                sb.Append($"<td style='padding:9px 12px;font-size:13px;border-bottom:1px solid #f1f5f9;color:#475569;text-align:center;'>{p.Unidad}</td>");
                sb.Append("</tr>");
                i++;
            }

            sb.Append("</tbody></table>");
            return sb.ToString();
        }

        public static string BloqueObservacion(string observacion, TipoNotificacion tipo)
        {
            var (bg, border, color) = tipo switch
            {
                TipoNotificacion.Rechazo => ("#fef2f2", "#dc2626", "#7f1d1d"),
                TipoNotificacion.Aprobacion => ("#f0fdf4", "#16a34a", "#14532d"),
                TipoNotificacion.Recepcion => ("#ecfeff", "#0891b2", "#164e63"),
                _ => ("#eff6ff", "#1e40af", "#1e3a6e")
            };

            var titulo = tipo == TipoNotificacion.Rechazo
                ? "<p style='margin:0 0 6px;font-size:11px;font-weight:700;color:#dc2626;text-transform:uppercase;'>MOTIVO DE RECHAZO</p>"
                : string.Empty;

            return $"<div style=\"background:{bg};border-left:4px solid {border};border-radius:0 8px 8px 0;padding:12px 16px;margin-top:16px;color:{color};\">{titulo}<p style=\"margin:0;font-size:14px;\">{observacion}</p></div>";
        }
    }
}
